int maximum( int a, int b, int c){
	int k;
	if( a <= b )
		k = b;
	else 
		k = a;
	if( k <= c )
		return c;
	else
		return k;
}

void nw_kernel1(int *reference_d, int *input_itemsets_d, int *output_itemsets_d,
                int cols, int penalty, int blk, int block_width, int worksize,
                int offset_r, int offset_c)
{
    int input_itemsets_l[(BLOCK_SIZE+1)*(BLOCK_SIZE+1)];
    int reference_l[BLOCK_SIZE*BLOCK_SIZE];

    #pragma omp parallel num_threads(BLOCK_SIZE)
    {
        int tx = omp_get_thread_num();

        for (int bx = 0; bx < blk; bx++) {
            int base = offset_r * cols + offset_c;
            int b_index_x = bx;
            int b_index_y = blk - 1 - bx;

            int index   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (cols + 1);
            int index_n = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (1);
            int index_w = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (cols);
            int index_nw= base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

            if (tx == 0){
                input_itemsets_l[0*(BLOCK_SIZE+1) + tx] = input_itemsets_d[index_nw + tx];
            }
            #pragma omp barrier

            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                reference_l[ty*BLOCK_SIZE + tx] = reference_d[index + cols * ty];
            }
            #pragma omp barrier

            input_itemsets_l[(tx+1)*(BLOCK_SIZE+1) + 0] = input_itemsets_d[index_w + cols * tx];
            #pragma omp barrier

            input_itemsets_l[0*(BLOCK_SIZE+1) + (tx+1)] = input_itemsets_d[index_n];
            #pragma omp barrier

            for (int m = 0; m < BLOCK_SIZE; m++) {
                if (tx <= m) {
                    int t_index_x = tx + 1;
                    int t_index_y = m - tx + 1;

                    int val1 = input_itemsets_l[(t_index_y-1)*(BLOCK_SIZE+1) + (t_index_x-1)] + reference_l[(t_index_y-1)*BLOCK_SIZE + (t_index_x-1)];
                    int val2 = input_itemsets_l[(t_index_y)*(BLOCK_SIZE+1) + (t_index_x-1)] - penalty;
                    int val3 = input_itemsets_l[(t_index_y-1)*(BLOCK_SIZE+1) + (t_index_x)] - penalty;

                    input_itemsets_l[t_index_y*(BLOCK_SIZE+1) + t_index_x] = maximum(val1, val2, val3);
                }
                #pragma omp barrier
            }

            #pragma omp barrier

            for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
                if (tx <= m) {
                    int t_index_x = tx + BLOCK_SIZE - m;
                    int t_index_y = BLOCK_SIZE - tx;

                    int val1 = input_itemsets_l[(t_index_y-1)*(BLOCK_SIZE+1) + (t_index_x-1)] + reference_l[(t_index_y-1)*BLOCK_SIZE + (t_index_x-1)];
                    int val2 = input_itemsets_l[(t_index_y)*(BLOCK_SIZE+1) + (t_index_x-1)] - penalty;
                    int val3 = input_itemsets_l[(t_index_y-1)*(BLOCK_SIZE+1) + (t_index_x)] - penalty;

                    input_itemsets_l[t_index_y*(BLOCK_SIZE+1) + t_index_x] = maximum(val1, val2, val3);
                }
                #pragma omp barrier
            }

            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                input_itemsets_d[index + cols * ty] = input_itemsets_l[(ty+1)*(BLOCK_SIZE+1) + (tx+1)];
            }
        }
    }
}

